import { useCallback, useState, type Dispatch, type SetStateAction } from 'react';
import df from '../../styles/documentForm.module.css';

/** Selected row + insert copy after selection (parity Finance `handleCopyLine`). */
export function useMaterialLinesSelection<T extends object>(
  lines: T[],
  setLines: Dispatch<SetStateAction<T[]>>,
) {
  const [selectedLineIndex, setSelectedLineIndex] = useState(0);

  const copyLine = useCallback(() => {
    if (lines.length === 0) return;
    const afterIdx =
      selectedLineIndex >= 0 && selectedLineIndex < lines.length
        ? selectedLineIndex
        : lines.length - 1;
    const source = lines[afterIdx];
    if (!source) return;
    const insertAt = afterIdx + 1;
    setLines(prev => {
      const next = [...prev];
      next.splice(insertAt, 0, { ...source });
      return next;
    });
    setSelectedLineIndex(insertAt);
  }, [lines, selectedLineIndex, setLines]);

  const lineRowProps = (idx: number) => ({
    className: [df.lineRow, selectedLineIndex === idx ? df.lineRowSelected : ''].filter(Boolean).join(' '),
    tabIndex: 0,
    onClick: () => setSelectedLineIndex(idx),
    onFocus: () => setSelectedLineIndex(idx),
  });

  return { selectedLineIndex, setSelectedLineIndex, copyLine, lineRowProps };
}
